  \node [state,right=of q1] (s2) {$s_{M_2}$};
  \node [right=1.5cm of s2] (M2) {$M_2$};
  \path [->] (q1) edge node[above] {$\varepsilon $} (s2);

  \path [dotted]
    (s1) edge (M1)
    (M1) edge (q1)
    (s2) edge (M2)
  ;

  \begin {scope}[on background layer]
